module SingleBitExtract(
  input  [3:0] a,
  output       b,
  output       c
);
  assign b = a[2];
  assign c = a[3];
endmodule

module RangeBitExtract(
  input  [3:0] a,
  output [2:0] c,
  output [1:0] d,
  output [1:0] e
);
  assign c = a[3:1];
  assign d = a[3:2];
  assign e = a[1:0];
endmodule

module SharedBitExtract(
  input  [3:0] a,
  output [1:0] f,
  output [1:0] j,
  output [1:0] s
);
  assign f = a[3:2];
  assign j = a[3:2];
  assign s = a[3:2];
endmodule

module NestedBitExtract(
  input  [3:0] a,
  output [1:0] f,
  output [1:0] g
);
  // f = bits(bits(a,3,1),2,1) => a[3:2]
  assign f = a[3:1][2:1];
  // g = bits(head(a,3),1,0) => a[2:1]
  assign g = a[3:1][1:0];
endmodule
